from flask import Flask, redirect, url_for, session, request, render_template_string
from functools import wraps

app = Flask(__name__)
app.secret_key = 'your_secret_key_here' # Güvenli bir anahtar kullanın

# Basit bir login formu için HTML string
LOGIN_FORM_HTML = """
<!doctype html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Login</title>
</head>
<body>
    <h2>Login</h2>
    <form method="post" action="{{ url_for('do_login') }}">
        <label for="username">Username:</label><br>
        <input type="text" id="username" name="username"><br>
        <label for="password">Password:</label><br>
        <input type="password" id="password" name="password"><br><br>
        <input type="submit" value="Login">
    </form>
    {% if error %}
        <p style="color:red;">{{ error }}</p>
    {% endif %}
</body>
</html>
"""

def login_required(f):
    @wraps(f)
    def wrap(*args, **kwargs):
        if 'logged_in' not in session or not session['logged_in']:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return wrap

@app.route('/')
def home():
    if 'logged_in' in session and session['logged_in']:
        return 'Merhaba, giriş yaptınız! <a href="/protected">Korumalı Sayfa</a> | <a href="/logout">Çıkış Yap</a>'
    return 'Ana Sayfa. <a href="/login">Giriş Yap</a>'

@app.route('/login', methods=['GET'])
def login():
    return render_template_string(LOGIN_FORM_HTML)

@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username')
    password = request.form.get('password')

    # Basit bir kullanıcı adı/şifre kontrolü
    if username == 'admin' and password == 'password':
        session['logged_in'] = True
        session['username'] = username
        return redirect(url_for('protected'))
    else:
        return render_template_string(LOGIN_FORM_HTML, error='Geçersiz kullanıcı adı veya şifre')

@app.route('/logout')
def logout():
    session.pop('logged_in', None)
    session.pop('username', None)
    return redirect(url_for('home'))

@app.route('/protected')
@login_required
def protected_page():
    return f'Bu korumalı bir sayfa, {session.get("username", "kullanıcı")} hoş geldiniz! <a href="/">Ana Sayfa</a> | <a href="/logout">Çıkış Yap</a>'

if __name__ == '__main__':
    app.run(debug=True)
